external_knowledge:
threatened creatures = species with 'Endangered' conservation status;
first category = species under 'Type 1';
typical weight = average adult mass.

sql:
SELECT AVG(adult_mass) AS average_adult_mass
FROM species
WHERE conservation_status = 'Endangered' AND annual_growth_rate > 2;

SELECT species_name 
FROM species 
WHERE conservation_status = 'Endangered' AND adult_mass > 50;

SELECT max_habitat_suitability, habitat_suitability_score
FROM habitat_suitability
WHERE max_habitat_suitability > 0.5;

SELECT AVG(adult_mass) AS average_adult_mass
FROM species
WHERE taxonomic_class = 'Aves';
